class Solution:
    def waysToReachStair(self, k: int) -> int:
        if k == 0:
            return 2
        from collections import deque
        visited = set()
        queue = deque()
        queue.append((1, 0, 0))  # (current stair, jump, last_operation)
        visited.add((1, 0))
        result = 0

        while queue:
            stair, jump, last_op = queue.popleft()
            if stair == k:
                result += 1
            # Go down
            if last_op != 1 and stair > 0:
                if (stair - 1, jump) not in visited:
                    visited.add((stair - 1, jump))
                    queue.append((stair - 1, jump, 1))
            # Go up
            new_stair = stair + (1 << jump)
            if (new_stair, jump + 1) not in visited:
                visited.add((new_stair, jump + 1))
                queue.append((new_stair, jump + 1, 2))
        return result
